import { formatDatetime } from "@/common/utils/formatting/datetime";
import type { IPalworldServerStateInfo } from "@/features/adapters/palworld/types/IPalworldServerStateInfo";
import type { IAdapterSpec } from "@/features/adapters/types/IAdapterSpec";
import type { IPlayer } from "@/features/player-log/types/IPlayer";
import type { IPlayerLog } from "@/features/player-log/types/IPlayerLog";
import type { IPlayerLogEntry } from "@/features/player-log/types/IPlayerLogEntry";
import type { IPlayerLogEvent } from "@/features/player-log/types/IPlayerLogEvent";

const PALWORLD_RE = {
  // Seems the first letter can arrive on its own line in the logs, hence `R?`
  serverStarted: /R?unning Palworld dedicated server on :(\d+)/i,
  gameVersion: /Game version is v([.\d]+)/i,
  // Not currently supported
  serverSaved: /NOT_CURRENTLY_SUPPORTED/i,
  playerJoined:
    /\[LOG] (.+) joined the server. \(User id: (.+), Player id: (.+)\)/i,
  playerLeft: /\[LOG] (.+) left the server. \(User id: (.+)\)/i,
  includesUserInfo: /User id/i,
};

export const PALWORLD_ADAPTER_SPEC: IAdapterSpec<
  "palworld",
  IPalworldServerStateInfo
> = {
  id: "palworld",
  name: "Palworld",
  logo: {
    src: "data:image/png;base64,",
    height: 675,
    width: 1200,
    omitTextFromLogoBanner: true,
  },
  configSpecs: {
    "PalWorldSettings.ini": {
      type: "ini",
      indent: "\t",
      newline: "\r\n",
      newlineEof: true,
    },
  },
  stateInfoSpec: {
    categorizeLogLine: (line) => {
      if (PALWORLD_RE.serverSaved.test(line)) return "save";
      if (
        PALWORLD_RE.playerJoined.test(line) ||
        PALWORLD_RE.playerLeft.test(line) ||
        PALWORLD_RE.includesUserInfo.test(line)
      )
        return "player";
      if (/error/i.test(line)) return "error";
      return undefined;
    },
    checkStarted: (data, _current) => PALWORLD_RE.serverStarted.test(data),
    infoGetters: [
      (data, _current) => ({
        gameVersion: data.match(PALWORLD_RE.gameVersion)?.[1],
      }),
      (data, _current) => ({
        port: data.match(PALWORLD_RE.serverStarted)?.[1],
      }),
      (data, _current) => {
        if (PALWORLD_RE.playerJoined.test(data)) {
          return {
            lastLoggedOn: formatDatetime(new Date(), true),
          };
        }

        if (PALWORLD_RE.playerLeft.test(data)) {
          return {
            lastLoggedOff: formatDatetime(new Date(), true),
          };
        }

        return {};
      },
      (data, current) => {
        const playerLog: IPlayerLog = current?.playerLog ?? {
          players: {},
          currentPlayers: [],
          entries: [],
        };

        const players = new Set(
          current?.players ? current.players.split(", ") : [],
        );

        let playerId: string | undefined;
        let playerName: string | undefined;
        let playerLogEvent: IPlayerLogEvent | undefined;

        const joinedPlayerMatch = data.match(PALWORLD_RE.playerJoined);
        if (joinedPlayerMatch?.[2]) {
          playerId = joinedPlayerMatch[2];
          playerName = joinedPlayerMatch[1];
          playerLogEvent = "logged-on";

          players.add(playerId);
        }

        const leftPlayerMatch = data.match(PALWORLD_RE.playerLeft);
        if (leftPlayerMatch?.[2]) {
          playerId = leftPlayerMatch[2];
          playerName = leftPlayerMatch[1];
          playerLogEvent = "logged-off";

          players.delete(playerId);
        }

        if (playerId && playerLogEvent) {
          const player: IPlayer = {
            id: playerId,
            name: playerName,
            player: playerId,
          };

          playerLog.players[playerId] = player;

          const nextCurrentPlayersSet = new Set(playerLog.currentPlayers);
          if (playerLogEvent === "logged-on") {
            nextCurrentPlayersSet.add(playerId);
          } else {
            nextCurrentPlayersSet.delete(playerId);
          }

          const playerLogEntry: IPlayerLogEntry = {
            id: playerId,
            event: playerLogEvent,
            timestamp: new Date(),
            prevCurrentPlayers: [...playerLog.currentPlayers],
            nextCurrentPlayers: Array.from(nextCurrentPlayersSet),
          };

          playerLog.currentPlayers = Array.from(nextCurrentPlayersSet);

          playerLog.entries.unshift(playerLogEntry);
        }

        return {
          players: Array.from(players).join(", "),
          playerCount: players.size,
          playerLog,
        };
      },
    ],
  },
};
